<template>
  <!-- Drag Handle -->
  <v-icon
    v-if="sortable && !disabled"
    name="drag_indicator"
    class="drag-handle"
    @click.stop
  />

  <!-- Collection Icon with Dirty/New Indicator -->
  <div class="icon-wrapper">
    <v-icon
      :name="collectionIcon || 'box'"
      class="collection-icon"
    />
    <div
      v-if="isNew"
      class="new-indicator"
      v-tooltip="'New block'"
    />
    <div
      v-else-if="isDirty"
      class="dirty-indicator"
      v-tooltip="'Unsaved changes'"
    />
  </div>

  <!-- Main Info Section -->
  <div class="block-info">
    <div class="block-main">
      <span class="block-title">{{ title }}</span>
      <v-chip x-small outline class="collection-chip">
        {{ collectionName }}
      </v-chip>
      <span v-if="showItemId && !isNew" class="item-id">
        ID: {{ itemId }}
      </span>
      
      <!-- Usage Indicator -->
      <v-chip
        v-if="usageCount && usageCount > 0"
        x-small
        class="usage-indicator"
        v-tooltip="usageTooltip"
      >
        <v-icon name="link" x-small />
        {{ usageCount }}
      </v-chip>
    </div>

    <!-- Status Display -->
    <slot name="status" />
  </div>

  <!-- Right Section -->
  <div class="block-actions">
    <!-- Expand/Collapse Icon or Placeholder -->
    <div class="expand-icon-container">
      <v-icon
        v-if="isExpanded"
        name="unfold_less"
        class="expand-indicator"
        @click.stop="$emit('toggle-expand')"
      />
    </div>

    <!-- More Options Menu -->
    <slot name="actions" />
  </div>
</template>

<script setup lang="ts">
import { computed } from 'vue';

interface Props {
  sortable: boolean;
  disabled: boolean;
  collectionIcon: string | null;
  isNew: boolean;
  isDirty: boolean;
  title: string;
  collectionName: string;
  showItemId: boolean;
  itemId: string | number;
  isExpanded: boolean;
  usageCount?: number;
  usageData?: {
    usageCount: number;
    externalCount: number;
    internalCount: number;
  };
}

const props = defineProps<Props>();

defineEmits<{
  'toggle-expand': [];
}>();

const usageTooltip = computed(() => {
  if (!props.usageData) {
    return `This item is used in ${props.usageCount} ${props.usageCount === 1 ? 'place' : 'places'}`;
  }
  
  const { externalCount, internalCount } = props.usageData;
  
  if (externalCount > 0 && internalCount > 0) {
    return `Used in ${externalCount} other ${externalCount === 1 ? 'place' : 'places'} and ${internalCount} more ${internalCount === 1 ? 'time' : 'times'} in this page`;
  } else if (externalCount > 0) {
    return `Used in ${externalCount} other ${externalCount === 1 ? 'place' : 'places'}`;
  } else {
    return `Used ${internalCount} more ${internalCount === 1 ? 'time' : 'times'} in this page`;
  }
});
</script>

<style scoped>
.usage-indicator {
  background-color: var(--warning-10);
  color: var(--warning);
  border-color: var(--warning-25);
  margin-left: 8px;
  
  :deep(.v-icon) {
    margin-right: 4px;
    color: var(--warning);
  }
}
</style>
